{"code": "import json
import os

# Find JSON files in the current directory tree
json_files = []
for root, dirs, files in os.walk('.'):
    for file in files:
        if file.endswith('.json'):
            path = os.path.join(root, file)
            json_files.append(path)

print('Found JSON files:')
for f in json_files:
    print(f'  {f}')

# Try to identify which files are our data
languages_file = None
readme_file = None

for f in json_files:
    with open(f, 'r') as file:
        try:
            data = json.load(file)
            if data and isinstance(data, list):
                first_item = data[0]
                if isinstance(first_item, dict):
                    if 'language_description' in first_item:
                        languages_file = f
                        print(f'Identified languages file: {f}')
                    elif 'sample_path' in first_item and 'content' in first_item:
                        readme_file = f
                        print(f'Identified readme file: {f}')
        except:
            pass

print('\n' + '='*50)
print(f'Languages file: {languages_file}')
print(f'README file: {readme_file}')

result = {
    'languages_file': languages_file,
    'readme_file': readme_file,
    'languages_found': languages_file is not None,
    'readme_found': readme_file is not None
}

print('__RESULT__:')
print(json.dumps(result))"}

